    matchAnalysisDecisionLabel === 'Apply now'
      ? 'border-emerald-500/30 bg-emerald-500/10 text-emerald-100'
      : matchAnalysisDecisionLabel === 'Prepare before applying'
        ? 'border-amber-500/30 bg-amber-500/10 text-amber-100'
