      ),
    [deferredQuery, overview.recentDeliveryIssues]
  );

  const filteredRecentAttempts = useMemo(
    () =>
      overview.recentAttempts.filter((attempt) =>
        includeQuery(
          [
            attempt.campaignName ?? '',
            attempt.emailAddress,
            attempt.domain,
            attempt.status,
            attempt.provider ?? '',
            attempt.failureCategory ?? '',
            attempt.message,
