          deferredQuery
        )
      ),
    [deferredQuery, overview.recentAttempts]
  );
  const filteredScheduledRetries = useMemo(
    () =>
      overview.scheduledRetries.filter((retry) =>
        includeQuery(
          [
            retry.campaignName ?? '',
            retry.emailAddress,
            retry.domain,
            retry.failureCategory ?? '',
            retry.status,
            retry.runId,
