const RECENT_THREAD_PREVIEW_LIMIT = 5;

const resolveStateAction = <State,>(
  nextState: React.SetStateAction<State>,
  previousState: State
): State =>
  typeof nextState === 'function'
    ? (nextState as (currentState: State) => State)(previousState)
    : nextState;

const isSameMailPageSelection = (
  left: MailPageSelection,
  right: MailPageSelection
): boolean =>
  left.accountId === right.accountId &&
  left.mailboxPath === right.mailboxPath &&
  left.panel === right.panel;

export interface MailPageState {
  accounts: FilemakerMailAccount[];
  setAccounts: React.Dispatch<React.SetStateAction<FilemakerMailAccount[]>>;
  folders: FilemakerMailFolderSummary[];
  threads: FilemakerMailThread[];
  recentPreviewThreads: FilemakerMailThread[];
  selection: MailPageSelection;
  setSelection: React.Dispatch<React.SetStateAction<MailPageSelection>>;
  selectedAccountId: MailPageSelection['accountId'];
  selectedMailboxPath: MailPageSelection['mailboxPath'];
  selectedPanel: MailPageSelection['panel'];
  isNavigationLoading: boolean;
  isThreadsLoading: boolean;
  isSavingAccount: boolean;
  syncingAccountId: string | null;
  setSyncingAccountId: React.Dispatch<React.SetStateAction<string | null>>;
  draft: FilemakerMailAccountDraft;
  setDraft: React.Dispatch<React.SetStateAction<FilemakerMailAccountDraft>>;
  accountFormErrors: FilemakerMailAccountDraftFieldErrors;
  deepSearchQuery: string;
  setDeepSearchQuery: React.Dispatch<React.SetStateAction<string>>;
  deepSearchResults: FilemakerMailSearchResponse | null;
  setDeepSearchResults: React.Dispatch<React.SetStateAction<FilemakerMailSearchResponse | null>>;
  isSearching: boolean;
  folderAllowlistValue: string;
  setFolderAllowlistValue: React.Dispatch<React.SetStateAction<string>>;
  query: string;
  setQuery: React.Dispatch<React.SetStateAction<string>>;
  recentMailboxFilter: string;
  setRecentMailboxFilter: React.Dispatch<React.SetStateAction<string>>;
  recentUnreadOnly: boolean;
  setRecentUnreadOnly: React.Dispatch<React.SetStateAction<boolean>>;
  recentCampaignId: string;
  recentRunId: string;
  recentDeliveryId: string;
  attentionAccounts: FilemakerMailAccount[];
  selectedAccount: FilemakerMailAccount | null;
  selectedFolder: FilemakerMailFolderSummary | null;
  selectedAccountLabel: string;
  selectedFolderLabel: string | null;
  isAttentionPanel: boolean;
  isSearchPanel: boolean;
  isRecentPanel: boolean;
  columns: ColumnDef<FilemakerMailThread>[];
  recentMailboxOptions: { value: string; label: string }[];
  visibleThreads: FilemakerMailThread[];
  tableActions: PanelAction[];
  handleSaveAccount: () => Promise<void>;
  handleSyncAccount: (accountId: string) => Promise<void>;
  loadNavigation: () => Promise<void>;
  onNewMailbox: () => void;
  router: ReturnType<typeof useRouter>;
}

export function useAdminFilemakerMailPageState(): MailPageState {
  const router = useRouter();
  const searchParams = useSearchParams();
  const { toast } = useToast();

  const rawRequestedAccountId = searchParams.get('accountId');
  const rawRequestedMailboxPath = searchParams.get('mailboxPath');
  const rawRequestedPanel = searchParams.get('panel');
  const rawRequestedSearchQuery = searchParams.get('searchQuery') ?? '';
  const rawRequestedRecentMailboxFilter = searchParams.get('recentMailbox') ?? '';
  const rawRequestedRecentUnreadOnly = searchParams.get('recentUnread') === '1';
  const rawRequestedRecentQuery = searchParams.get('recentQuery') ?? '';
  const rawRequestedRecentCampaignId = searchParams.get('campaignId') ?? '';
  const rawRequestedRecentRunId = searchParams.get('runId') ?? '';
  const rawRequestedRecentDeliveryId = searchParams.get('deliveryId') ?? '';

  const requestedPanel =
    rawRequestedPanel === 'attention'
      ? 'attention'
      : rawRequestedPanel === 'settings' || rawRequestedPanel === 'account'
      ? 'settings'
      : rawRequestedPanel === 'recent'
        ? 'recent'
        : rawRequestedPanel === 'search'
          ? 'search'
          : rawRequestedAccountId && !rawRequestedMailboxPath
            ? 'settings'
            : null;

  const requestedAccountId = requestedPanel === 'attention' ? null : rawRequestedAccountId;
  const requestedMailboxPath = requestedPanel ? null : rawRequestedMailboxPath;

  const [query, setQueryState] = useState('');
  const nonRecentQueryScopeKeyRef = useRef<string | null>(null);
  const [accounts, setAccounts] = useState<FilemakerMailAccount[]>([]);
  const [folders, setFolders] = useState<FilemakerMailFolderSummary[]>([]);
  const [threads, setThreads] = useState<FilemakerMailThread[]>([]);
  const [recentPreviewThreads, setRecentPreviewThreads] = useState<FilemakerMailThread[]>([]);
  const [recentMailboxFilter, setRecentMailboxFilterState] = useState('');
  const [recentUnreadOnly, setRecentUnreadOnlyState] = useState(false);
  const [recentCampaignId, setRecentCampaignIdState] = useState(
    rawRequestedPanel === 'recent' ? rawRequestedRecentCampaignId : ''
  );
  const [recentRunId, setRecentRunIdState] = useState(
    rawRequestedPanel === 'recent' ? rawRequestedRecentRunId : ''
  );
  const [recentDeliveryId, setRecentDeliveryIdState] = useState(
    rawRequestedPanel === 'recent' ? rawRequestedRecentDeliveryId : ''
  );
  const [selection, setSelectionState] = useState<MailPageSelection>({
    accountId: requestedAccountId,
    mailboxPath: requestedMailboxPath,
    panel: requestedPanel,
  });
  const shouldIgnoreActiveSearchState =
    rawRequestedPanel === 'search' &&
    selection.panel === 'search' &&
    (rawRequestedAccountId ?? null) !== (selection.accountId ?? null);
  const shouldIgnoreActiveRecentState =
    rawRequestedPanel === 'recent' &&
    selection.panel === 'recent' &&
    rawRequestedAccountId !== selection.accountId;
  const shouldIgnoreRequestedSearchState =
    rawRequestedPanel === 'search' &&
    (selection.panel !== 'search' ||
      (rawRequestedAccountId ?? null) !== (selection.accountId ?? null));
  const requestedSearchQuery =
    requestedPanel === 'search' && !shouldIgnoreRequestedSearchState
      ? rawRequestedSearchQuery
      : '';
  const shouldIgnoreRequestedRecentState =
    rawRequestedPanel === 'recent' &&
    (selection.panel !== 'recent' || rawRequestedAccountId !== selection.accountId);
  const requestedRecentMailboxFilter =
    requestedPanel === 'recent' && !shouldIgnoreRequestedRecentState
      ? rawRequestedRecentMailboxFilter
      : '';
  const requestedRecentUnreadOnly =
    requestedPanel === 'recent' && !shouldIgnoreRequestedRecentState
      ? rawRequestedRecentUnreadOnly
      : false;
  const requestedRecentQuery =
    requestedPanel === 'recent' && !shouldIgnoreRequestedRecentState
      ? rawRequestedRecentQuery
      : '';
  const requestedRecentCampaignId =
    requestedPanel === 'recent' && !shouldIgnoreRequestedRecentState
      ? rawRequestedRecentCampaignId
      : '';
  const requestedRecentRunId =
    requestedPanel === 'recent' && !shouldIgnoreRequestedRecentState
      ? rawRequestedRecentRunId
      : '';
  const requestedRecentDeliveryId =
    requestedPanel === 'recent' && !shouldIgnoreRequestedRecentState
      ? rawRequestedRecentDeliveryId
      : '';
  const requestedSelection = useMemo(
    () =>
      ({
        accountId: requestedAccountId,
        mailboxPath: requestedMailboxPath,
        panel: requestedPanel,
      }) satisfies MailPageSelection,
    [requestedAccountId, requestedMailboxPath, requestedPanel]
  );
  const requestedSelectionHref = buildMailSelectionHref({
    accountId: requestedAccountId,
    mailboxPath: requestedMailboxPath,
    panel: requestedPanel,
    recentMailboxFilter: requestedRecentMailboxFilter,
    recentUnreadOnly: requestedRecentUnreadOnly,
    recentQuery: requestedRecentQuery,
    recentCampaignId: requestedRecentCampaignId,
    recentRunId: requestedRecentRunId,
    recentDeliveryId: requestedRecentDeliveryId,
    searchQuery: requestedSearchQuery,
  });
  const effectiveQuery = shouldIgnoreActiveRecentState ? '' : query;
  const effectiveRecentMailboxFilter = shouldIgnoreActiveRecentState ? '' : recentMailboxFilter;
  const effectiveRecentUnreadOnly = shouldIgnoreActiveRecentState ? false : recentUnreadOnly;
  const effectiveRecentCampaignId = shouldIgnoreActiveRecentState ? '' : recentCampaignId;
  const effectiveRecentRunId = shouldIgnoreActiveRecentState ? '' : recentRunId;
  const effectiveRecentDeliveryId = shouldIgnoreActiveRecentState ? '' : recentDeliveryId;
  const deferredQuery = useDeferredValue(query.trim());
  const currentNonRecentQueryScopeKey =
    selection.panel === 'recent'
      ? null
      : [selection.panel ?? '', selection.accountId ?? '', selection.mailboxPath ?? ''].join('::');
  const shouldIgnoreThreadQuery =
    shouldIgnoreActiveRecentState ||
    (rawRequestedPanel === 'recent' && selection.panel !== 'recent') ||
    (currentNonRecentQueryScopeKey !== null &&
      nonRecentQueryScopeKeyRef.current !== null &&
      nonRecentQueryScopeKeyRef.current !== currentNonRecentQueryScopeKey);
  const threadSourceQuery = shouldIgnoreThreadQuery ? '' : effectiveQuery.trim();
  const activeThreadQuery = threadSourceQuery === '' ? '' : deferredQuery;
  const [isNavigationLoading, setIsNavigationLoading] = useState(true);
  const [isThreadsLoading, setIsThreadsLoading] = useState(false);
  const [isSavingAccount, setIsSavingAccount] = useState(false);
  const [syncingAccountId, setSyncingAccountId] = useState<string | null>(null);
  const [draft, setDraft] = useState<FilemakerMailAccountDraft>(defaultDraft);
  const [accountFormErrors, setAccountFormErrors] =
    useState<FilemakerMailAccountDraftFieldErrors>({});
  const [deepSearchQuery, setDeepSearchQueryState] = useState(requestedSearchQuery);
  const effectiveDeepSearchQuery = shouldIgnoreActiveSearchState ? '' : deepSearchQuery;
  const [deepSearchResults, setDeepSearchResults] = useState<FilemakerMailSearchResponse | null>(null);
  const [isSearching, setIsSearching] = useState(false);
  const [folderAllowlistValue, setFolderAllowlistValue] = useState('');
  const navigationRequestIdRef = useRef(0);
  const threadsRequestIdRef = useRef(0);
  const threadsSourceKeyRef = useRef<string | null>(null);
  const deepSearchRequestIdRef = useRef(0);
  const deepSearchSourceKeyRef = useRef<string | null>(null);
  const recentPreviewAccountIdRef = useRef<string | null>(null);
  const routeSyncHrefRef = useRef<string | null>(null);
  const routeSyncSourceKeyRef = useRef<string | null>(null);
  const hasPendingRouteSync = routeSyncHrefRef.current !== null;
  const isPendingRequestedRouteStale =
    hasPendingRouteSync && routeSyncHrefRef.current !== requestedSelectionHref;
  const shouldHoldLocalSelectionFromRoute =
    isPendingRequestedRouteStale &&
    !isSameMailPageSelection(selection, requestedSelection);
  const shouldHoldLocalRecentStateFromRoute =
    isPendingRequestedRouteStale &&
    selection.panel === 'recent' &&
    (recentMailboxFilter !== requestedRecentMailboxFilter ||
      recentUnreadOnly !== requestedRecentUnreadOnly ||
      query !== requestedRecentQuery ||
      recentCampaignId !== requestedRecentCampaignId ||
      recentRunId !== requestedRecentRunId ||
      recentDeliveryId !== requestedRecentDeliveryId);
  const shouldHoldLocalSearchStateFromRoute =
    isPendingRequestedRouteStale &&
    selection.panel === 'search' &&
    deepSearchQuery !== requestedSearchQuery;

  const setSelection = useCallback<React.Dispatch<React.SetStateAction<MailPageSelection>>>(
    (nextSelection) => {
      setSelectionState((previousSelection) => {
        const resolvedSelection = resolveStateAction(nextSelection, previousSelection);
        return isSameMailPageSelection(previousSelection, resolvedSelection)
          ? previousSelection
          : resolvedSelection;
      });
    },
    []
  );

  const setQuery = useCallback<React.Dispatch<React.SetStateAction<string>>>((nextQuery) => {
    setQueryState((previousQuery) => {
      const resolvedQuery = resolveStateAction(nextQuery, previousQuery);
      return previousQuery === resolvedQuery ? previousQuery : resolvedQuery;
    });
  }, []);

  const setRecentMailboxFilter = useCallback<React.Dispatch<React.SetStateAction<string>>>(
    (nextMailboxFilter) => {
      setRecentMailboxFilterState((previousMailboxFilter) => {
        const resolvedMailboxFilter = resolveStateAction(
          nextMailboxFilter,
          previousMailboxFilter
        );
        return previousMailboxFilter === resolvedMailboxFilter
          ? previousMailboxFilter
          : resolvedMailboxFilter;
      });
    },
    []
  );

  const setRecentUnreadOnly = useCallback<React.Dispatch<React.SetStateAction<boolean>>>(
    (nextRecentUnreadOnly) => {
      setRecentUnreadOnlyState((previousRecentUnreadOnly) => {
        const resolvedRecentUnreadOnly = resolveStateAction(
          nextRecentUnreadOnly,
          previousRecentUnreadOnly
        );
        return previousRecentUnreadOnly === resolvedRecentUnreadOnly
          ? previousRecentUnreadOnly
          : resolvedRecentUnreadOnly;
      });
    },
    []
  );

  const setRecentCampaignId = useCallback<React.Dispatch<React.SetStateAction<string>>>(
    (nextRecentCampaignId) => {
      setRecentCampaignIdState((previousRecentCampaignId) => {
        const resolvedRecentCampaignId = resolveStateAction(
          nextRecentCampaignId,
          previousRecentCampaignId
        );
        return previousRecentCampaignId === resolvedRecentCampaignId
          ? previousRecentCampaignId
          : resolvedRecentCampaignId;
      });
    },
    []
  );

  const setRecentRunId = useCallback<React.Dispatch<React.SetStateAction<string>>>(
    (nextRecentRunId) => {
      setRecentRunIdState((previousRecentRunId) => {
        const resolvedRecentRunId = resolveStateAction(nextRecentRunId, previousRecentRunId);
        return previousRecentRunId === resolvedRecentRunId
          ? previousRecentRunId
          : resolvedRecentRunId;
      });
    },
    []
  );

  const setRecentDeliveryId = useCallback<React.Dispatch<React.SetStateAction<string>>>(
    (nextRecentDeliveryId) => {
      setRecentDeliveryIdState((previousRecentDeliveryId) => {
        const resolvedRecentDeliveryId = resolveStateAction(
          nextRecentDeliveryId,
          previousRecentDeliveryId
        );
        return previousRecentDeliveryId === resolvedRecentDeliveryId
          ? previousRecentDeliveryId
          : resolvedRecentDeliveryId;
      });
    },
    []
  );

  const setDeepSearchQuery = useCallback<React.Dispatch<React.SetStateAction<string>>>(
    (nextDeepSearchQuery) => {
      setDeepSearchQueryState((previousDeepSearchQuery) => {
        const resolvedDeepSearchQuery = resolveStateAction(
          nextDeepSearchQuery,
          previousDeepSearchQuery
        );
        return previousDeepSearchQuery === resolvedDeepSearchQuery
          ? previousDeepSearchQuery
          : resolvedDeepSearchQuery;
      });
    },
    []
  );

  const selectedAccountId = selection.accountId;
  const selectedMailboxPath = selection.mailboxPath;
  const selectedPanel = selection.panel;

  const attentionAccounts = useMemo(
    () =>
      accounts.filter(
        (account) => account.status !== 'active' || Boolean(account.lastSyncError?.trim())
      ),
    [accounts]
  );

  const selectedAccount = useMemo(() => {
    return accounts.find((account) => account.id === selectedAccountId) ?? null;
  }, [accounts, selectedAccountId]);

  const selectedFolder = useMemo(() => {
    if (!selectedAccountId || !selectedMailboxPath) return null;
    return (
      folders.find(
        (folder) =>
          folder.accountId === selectedAccountId &&
          folder.mailboxPath === selectedMailboxPath
      ) ?? null
    );
  }, [folders, selectedAccountId, selectedMailboxPath]);

  const loadNavigation = useCallback(async (): Promise<void> => {
    const requestId = navigationRequestIdRef.current + 1;
    navigationRequestIdRef.current = requestId;
    setIsNavigationLoading(true);
    try {
      const [accountsResult, foldersResult] = await Promise.all([
        fetchJson<AccountsResponse>('/api/filemaker/mail/accounts'),
        fetchJson<FoldersResponse>('/api/filemaker/mail/folders'),
      ]);
      if (requestId !== navigationRequestIdRef.current) {
        return;
      }
      setAccounts(accountsResult.accounts);
      setFolders(foldersResult.folders);
    } catch (error) {
      if (requestId !== navigationRequestIdRef.current) {
        return;
      }
      toast(error instanceof Error ? error.message : 'Failed to load Filemaker mail.', {
        variant: 'error',
      });
    } finally {
      if (requestId === navigationRequestIdRef.current) {
        setIsNavigationLoading(false);
      }
    }
  }, [toast]);

  useEffect(() => {
    void loadNavigation();
  }, [loadNavigation]);

  useEffect(() => {
    if (shouldHoldLocalSelectionFromRoute) {
      return;
    }
    setSelection(requestedSelection);
  }, [
    requestedSelection,
    setSelection,
    shouldHoldLocalSelectionFromRoute,
  ]);

  useEffect(() => {
    if (shouldHoldLocalRecentStateFromRoute) {
      return;
    }
    setRecentMailboxFilter(requestedRecentMailboxFilter);
    setRecentUnreadOnly(requestedRecentUnreadOnly);
    setRecentCampaignId(requestedRecentCampaignId);
    setRecentRunId(requestedRecentRunId);
    setRecentDeliveryId(requestedRecentDeliveryId);
  }, [
    requestedRecentCampaignId,
    requestedRecentDeliveryId,
    requestedRecentMailboxFilter,
    requestedRecentRunId,
    requestedRecentUnreadOnly,
    setRecentCampaignId,
    setRecentDeliveryId,
    setRecentMailboxFilter,
    setRecentRunId,
    setRecentUnreadOnly,
    shouldHoldLocalRecentStateFromRoute,
  ]);

  useEffect(() => {
    if (shouldHoldLocalSearchStateFromRoute) {
      return;
    }
    setDeepSearchQuery(requestedSearchQuery);
  }, [requestedSearchQuery, setDeepSearchQuery, shouldHoldLocalSearchStateFromRoute]);

  useEffect(() => {
    if (shouldHoldLocalRecentStateFromRoute) {
      return;
    }
    setQuery(requestedPanel === 'recent' ? requestedRecentQuery : '');
  }, [requestedPanel, requestedRecentQuery, setQuery, shouldHoldLocalRecentStateFromRoute]);

  useLayoutEffect(() => {
    if (selection.panel !== 'recent') {
      setRecentMailboxFilter('');
      setRecentUnreadOnly(false);
      setRecentCampaignId('');
      setRecentRunId('');
      setRecentDeliveryId('');
      setQuery('');
    }
    if (selection.panel !== 'search') {
      setDeepSearchQuery('');
    }
  }, [
    selection.panel,
    setDeepSearchQuery,
    setQuery,
    setRecentCampaignId,
    setRecentDeliveryId,
    setRecentMailboxFilter,
    setRecentRunId,
    setRecentUnreadOnly,
  ]);

  useLayoutEffect(() => {
    if (selection.panel === 'recent') {
      nonRecentQueryScopeKeyRef.current = null;
      return;
    }

    const nextNonRecentQueryScopeKey = [
      selection.panel ?? '',
      selectedAccountId ?? '',
      selectedFolder?.mailboxPath ?? '',
    ].join('::');

    if (nonRecentQueryScopeKeyRef.current !== nextNonRecentQueryScopeKey) {
      nonRecentQueryScopeKeyRef.current = nextNonRecentQueryScopeKey;
      setQuery('');
    }
  }, [selectedAccountId, selectedFolder?.mailboxPath, selection.panel, setQuery]);

  useEffect(() => {
    if (!selectedAccount) {
      setDraft(defaultDraft());
      setFolderAllowlistValue('');
      return;
    }
    setDraft(toDraftFromAccount(selectedAccount));
    setFolderAllowlistValue(formatFilemakerMailboxAllowlist(selectedAccount.folderAllowlist));
  }, [selectedAccount]);

  useEffect(() => {
    setAccountFormErrors({});
  }, [draft, folderAllowlistValue]);

  useEffect(() => {
    if (!selectedAccountId || (!selectedFolder && selection.panel !== 'recent')) {
      threadsRequestIdRef.current += 1;
      threadsSourceKeyRef.current = null;
      setIsThreadsLoading(false);
      setThreads([]);
      return;
    }

    const nextThreadsSourceKey = [
      selectedAccountId,
      selection.panel ?? '',
      selectedFolder?.mailboxPath ?? '',
      threadSourceQuery,
      effectiveRecentCampaignId,
      effectiveRecentRunId,
      effectiveRecentDeliveryId,
    ].join('::');
    if (threadsSourceKeyRef.current !== nextThreadsSourceKey) {
      threadsRequestIdRef.current += 1;
      threadsSourceKeyRef.current = nextThreadsSourceKey;
      setIsThreadsLoading(true);
      setThreads([]);
    }
  }, [
    effectiveRecentCampaignId,
    effectiveRecentDeliveryId,
    effectiveRecentRunId,
    selectedAccountId,
    selectedFolder,
    selection.panel,
    threadSourceQuery,
  ]);

  useEffect(() => {
    if (!selectedAccountId || (!selectedFolder && selection.panel !== 'recent')) {
      setIsThreadsLoading(false);
      return;
    }

    const requestId = threadsRequestIdRef.current + 1;
    threadsRequestIdRef.current = requestId;

    const loadThreads = async (): Promise<void> => {
      setIsThreadsLoading(true);
      try {
        const params = new URLSearchParams({ accountId: selectedAccountId });
        if (selection.panel === 'recent') {
          if (activeThreadQuery !== '') params.set('query', activeThreadQuery);
          if (effectiveRecentCampaignId !== '') params.set('campaignId', effectiveRecentCampaignId);
          if (effectiveRecentRunId !== '') params.set('runId', effectiveRecentRunId);
          if (effectiveRecentDeliveryId !== '') params.set('deliveryId', effectiveRecentDeliveryId);
        } else {
          params.set('mailboxPath', selectedFolder?.mailboxPath ?? '');
          if (activeThreadQuery !== '') params.set('query', activeThreadQuery);
        }
        const result = await fetchJson<ThreadsResponse>(
          `/api/filemaker/mail/threads?${params.toString()}`
        );
        if (requestId !== threadsRequestIdRef.current) {
          return;
        }
        setThreads(result.threads);
      } catch (error) {
        if (requestId !== threadsRequestIdRef.current) {
          return;
        }
        toast(error instanceof Error ? error.message : 'Failed to load mail threads.', {
          variant: 'error',
        });
      } finally {
        if (requestId === threadsRequestIdRef.current) {
          setIsThreadsLoading(false);
        }
      }
    };

    void loadThreads();
  }, [
    activeThreadQuery,
    effectiveRecentCampaignId,
    effectiveRecentDeliveryId,
    effectiveRecentRunId,
    selectedAccountId,
    selectedFolder,
    selection.panel,
    toast,
  ]);

  useEffect(() => {
    if (isNavigationLoading) return;
    if (!selectedAccountId) {
      recentPreviewAccountIdRef.current = null;
      setRecentPreviewThreads([]);
      return;
    }

    if (recentPreviewAccountIdRef.current !== selectedAccountId) {
      recentPreviewAccountIdRef.current = selectedAccountId;
      setRecentPreviewThreads([]);
    }

    let isActive = true;

    const loadRecentPreviewThreads = async (): Promise<void> => {
      try {
        const params = new URLSearchParams({
          accountId: selectedAccountId,
          limit: String(RECENT_THREAD_PREVIEW_LIMIT),
        });
        const result = await fetchJson<ThreadsResponse>(
          `/api/filemaker/mail/threads?${params.toString()}`
        );
        if (!isActive) {
          return;
        }
        setRecentPreviewThreads(result.threads);
      } catch (error) {
        if (!isActive) {
          return;
        }
        setRecentPreviewThreads([]);
        toast(error instanceof Error ? error.message : 'Failed to load recent thread preview.', {
          variant: 'error',
        });
      }
    };

    void loadRecentPreviewThreads();

    return () => {
      isActive = false;
    };
  }, [accounts, isNavigationLoading, selectedAccountId, toast]);

  const deferredDeepSearch = useDeferredValue(effectiveDeepSearchQuery.trim());
  const deepSearchSourceQuery = effectiveDeepSearchQuery.trim();
  const activeDeepSearchQuery = deepSearchSourceQuery === '' ? '' : deferredDeepSearch;

  useEffect(() => {
    if (selection.panel !== 'search') {
      deepSearchSourceKeyRef.current = null;
      return;
    }
    if (deepSearchSourceQuery === '') {
      deepSearchSourceKeyRef.current = null;
      return;
    }

    const nextDeepSearchSourceKey = [selectedAccountId ?? 'all', deepSearchSourceQuery].join('::');
    if (deepSearchSourceKeyRef.current !== nextDeepSearchSourceKey) {
      deepSearchSourceKeyRef.current = nextDeepSearchSourceKey;
      setDeepSearchResults(null);
      setIsSearching(true);
    }
  }, [deepSearchSourceQuery, selectedAccountId, selection.panel]);

  useEffect(() => {
    if (selection.panel !== 'search') {
      deepSearchRequestIdRef.current += 1;
      setIsSearching(false);
      setDeepSearchResults(null);
      return;
    }
    if (activeDeepSearchQuery === '') {
      deepSearchRequestIdRef.current += 1;
      setIsSearching(false);
      setDeepSearchResults(null);
      return;
    }

    const requestId = deepSearchRequestIdRef.current + 1;
    deepSearchRequestIdRef.current = requestId;

    const runSearch = async (): Promise<void> => {
      setIsSearching(true);
      try {
        const url = `/api/filemaker/mail/search?query=${encodeURIComponent(activeDeepSearchQuery)}${
          selectedAccountId ? `&accountId=${encodeURIComponent(selectedAccountId)}` : ''
        }`;
        const result = await fetchJson<FilemakerMailSearchResponse>(url);
        if (requestId !== deepSearchRequestIdRef.current) {
          return;
        }
        setDeepSearchResults(result);
      } catch (error) {
        if (requestId !== deepSearchRequestIdRef.current) {
          return;
        }
        toast(error instanceof Error ? error.message : 'Message search failed.', {
          variant: 'error',
        });
      } finally {
        if (requestId === deepSearchRequestIdRef.current) {
          setIsSearching(false);
        }
      }
    };

    void runSearch();
  }, [activeDeepSearchQuery, selectedAccountId, selection.panel, toast]);

  useEffect(() => {
    if (isNavigationLoading) return;
    if (selection.panel === 'attention') return;
    if (selection.panel === 'search') return;
    if (selection.accountId && selection.panel === 'recent' && selectedAccount) return;
    if (selection.accountId && selection.mailboxPath && selectedFolder) return;
    if (selection.accountId && !selection.mailboxPath && selectedAccount) return;

    const nextSelection: typeof selection | null =
      selection.accountId && selection.mailboxPath
        ? accounts.some((account) => account.id === selection.accountId)
          ? {
              accountId: selection.accountId,
              mailboxPath: null as string | null,
              panel: selection.panel === 'recent' ? 'recent' : selection.panel,
            }
          : { accountId: null, mailboxPath: null, panel: null }
        : selection.accountId && !selectedAccount
          ? { accountId: null, mailboxPath: null, panel: null }
          : null;

    if (!nextSelection) {
      return;
    }
    setSelection(nextSelection);
  }, [
    accounts,
    isNavigationLoading,
    selectedAccount,
    selectedFolder,
    selection.accountId,
    selection.mailboxPath,
    selection.panel,
  ]);

  useEffect(() => {
    if (isNavigationLoading) return;
    const nextPanel = selection.panel ?? null;
    const nextAccountId = nextPanel === 'attention' ? null : selection.accountId ?? null;
    const nextMailboxPath = nextPanel ? null : selection.mailboxPath ?? null;
    const nextRecentMailboxFilter = nextPanel === 'recent' ? effectiveRecentMailboxFilter : '';
    const nextRecentUnreadOnly = nextPanel === 'recent' ? effectiveRecentUnreadOnly : false;
    const nextRecentQuery = nextPanel === 'recent' ? effectiveQuery : '';
    const nextRecentCampaignId = nextPanel === 'recent' ? effectiveRecentCampaignId : '';
    const nextRecentRunId = nextPanel === 'recent' ? effectiveRecentRunId : '';
    const nextRecentDeliveryId = nextPanel === 'recent' ? effectiveRecentDeliveryId : '';
    const nextSearchQuery = nextPanel === 'search' ? effectiveDeepSearchQuery : '';
    const nextHref = buildMailSelectionHref({
      accountId: nextAccountId,
      mailboxPath: nextMailboxPath,
      panel: nextPanel,
      recentMailboxFilter: nextRecentMailboxFilter,
      recentUnreadOnly: nextRecentUnreadOnly,
      recentQuery: nextRecentQuery,
      recentCampaignId: nextRecentCampaignId,
      recentRunId: nextRecentRunId,
      recentDeliveryId: nextRecentDeliveryId,
      searchQuery: nextSearchQuery,
    });
    const currentRouteStateKey = [
      rawRequestedAccountId ?? '',
      rawRequestedMailboxPath ?? '',
      rawRequestedPanel ?? '',
      rawRequestedRecentMailboxFilter,
      rawRequestedRecentUnreadOnly ? '1' : '0',
      rawRequestedRecentQuery,
      rawRequestedRecentCampaignId,
      rawRequestedRecentRunId,
      rawRequestedRecentDeliveryId,
      rawRequestedSearchQuery,
    ].join('::');
    if (
      (rawRequestedAccountId ?? null) === nextAccountId &&
      (rawRequestedMailboxPath ?? null) === nextMailboxPath &&
      (rawRequestedPanel ?? null) === nextPanel &&
      rawRequestedRecentMailboxFilter === nextRecentMailboxFilter &&
      rawRequestedRecentUnreadOnly === nextRecentUnreadOnly &&
      rawRequestedRecentQuery === nextRecentQuery &&
      rawRequestedRecentCampaignId === nextRecentCampaignId &&
      rawRequestedRecentRunId === nextRecentRunId &&
      rawRequestedRecentDeliveryId === nextRecentDeliveryId &&
      rawRequestedSearchQuery === nextSearchQuery
    ) {
      routeSyncHrefRef.current = null;
      routeSyncSourceKeyRef.current = null;
      return;
    }
    if (
      routeSyncHrefRef.current === nextHref &&
      routeSyncSourceKeyRef.current === currentRouteStateKey
    ) {
      return;
    }
    routeSyncHrefRef.current = nextHref;
    routeSyncSourceKeyRef.current = currentRouteStateKey;
    startTransition(() => {
      router.replace(nextHref);
    });
  }, [
    effectiveDeepSearchQuery,
    effectiveRecentCampaignId,
    effectiveRecentDeliveryId,
    effectiveQuery,
    effectiveRecentMailboxFilter,
    effectiveRecentRunId,
    effectiveRecentUnreadOnly,
    isNavigationLoading,
    rawRequestedAccountId,
    rawRequestedRecentCampaignId,
    rawRequestedRecentDeliveryId,
    rawRequestedMailboxPath,
    rawRequestedPanel,
    rawRequestedRecentMailboxFilter,
    rawRequestedRecentQuery,
    rawRequestedRecentRunId,
    rawRequestedRecentUnreadOnly,
    rawRequestedSearchQuery,
    router,
    selection.accountId,
    selection.mailboxPath,
    selection.panel,
  ]);

  const handleSaveAccount = useCallback(async (): Promise<void> => {
    const nextErrors = validateFilemakerMailAccountDraft(draft);
    if (hasFilemakerMailAccountDraftErrors(nextErrors)) {
      setAccountFormErrors(nextErrors);
      toast('Fill the highlighted mailbox fields and try again.', {
        variant: 'error',
      });
      return;
    }

    setIsSavingAccount(true);
    try {
      setAccountFormErrors({});
      const isCreate = !draft.id;
      const payload = {
        ...draft,
        folderAllowlist: folderAllowlistValue
          .split(',')
          .map((entry) => entry.trim())
          .filter(Boolean),
      };
      const result = await fetchJson<{ account: FilemakerMailAccount }>(
        '/api/filemaker/mail/accounts',
        {
          method: 'POST',
          body: JSON.stringify(payload),
        }
      );
      toast(draft.id ? 'Mailbox account updated.' : 'Mailbox account saved.', {
        variant: 'success',
      });

      if (isCreate) {
        try {
          const syncResult = await fetchJson<FilemakerMailSyncDispatchResponseLike>(
            `/api/filemaker/mail/accounts/${encodeURIComponent(result.account.id)}/sync`,
            { method: 'POST' }
          );
          const notice = resolveFilemakerMailSyncNotice(syncResult);
          toast(notice.message, { variant: notice.variant });
        } catch (error) {
          toast(
            error instanceof Error
              ? `Mailbox saved, but initial sync failed: ${error.message}`
              : 'Mailbox saved, but initial sync failed.',
            {
              variant: 'error',
            }
          );
        }
      }

      await loadNavigation();
      setSelection({ accountId: result.account.id, mailboxPath: null, panel: 'settings' });
    } catch (error) {
      toast(error instanceof Error ? error.message : 'Failed to save mailbox account.', {
        variant: 'error',
      });
    } finally {
      setIsSavingAccount(false);
    }
  }, [draft, folderAllowlistValue, loadNavigation, toast]);

  const onNewMailbox = useCallback(() => {
    setSelection({ accountId: null, mailboxPath: null, panel: 'settings' });
  }, []);

  const handleSyncAccount = useCallback(
    async (accountId: string): Promise<void> => {
      setSyncingAccountId(accountId);
      try {
        const result = await fetchJson<FilemakerMailSyncDispatchResponseLike>(
          `/api/filemaker/mail/accounts/${encodeURIComponent(accountId)}/sync`,
          { method: 'POST' }
        );
        const notice = resolveFilemakerMailSyncNotice(result);
        toast(notice.message, { variant: notice.variant });

        await loadNavigation();
      } catch (error) {
        toast(error instanceof Error ? error.message : 'Mailbox sync failed.', {
          variant: 'error',
        });
      } finally {
        setSyncingAccountId(null);
      }
    },
    [loadNavigation, toast]
  );

  const selectedAccountLabel = selectedAccount?.name ?? 'New mailbox account';
  const selectedFolderLabel = selectedFolder
    ? formatFilemakerMailFolderLabel(selectedFolder.mailboxPath, selectedFolder.mailboxRole)
    : null;
  const isAttentionPanel = selectedPanel === 'attention';
  const isSearchPanel = selectedPanel === 'search';
  const isRecentPanel = selectedPanel === 'recent' && !selectedFolder;

  const columns = useMemo<ColumnDef<FilemakerMailThread>[]>(
    () => [
      {
        id: 'subject',
        header: 'Thread',
        cell: ({ row }) => (
          <div className='min-w-0 space-y-1'>
            <div className='truncate text-sm font-semibold text-white'>{row.original.subject}</div>
            <div className='truncate text-[11px] text-gray-500'>
              {row.original.participantSummary
                .map((participant) => participant.name ?? participant.address)
                .join(', ')}
            </div>
            {row.original.snippet ? (
              <div className='line-clamp-2 text-[11px] text-gray-400'>{row.original.snippet}</div>
            ) : null}
          </div>
        ),
      },
      {
        id: 'mailbox',
        header: 'Mailbox',
        cell: ({ row }) => (
          <div className='space-y-0.5 text-[11px] text-gray-500'>
            <div>{row.original.mailboxPath}</div>
            <div className='capitalize'>Unread: {row.original.unreadCount}</div>
          </div>
        ),
      },
      {
        accessorKey: 'lastMessageAt',
        header: 'Last Activity',
        cell: ({ row }) => (
          <div className='text-[11px] text-gray-500'>
            {new Date(row.original.lastMessageAt).toLocaleString()}
          </div>
        ),
      },
      {
        id: 'actions',
        header: () => <div className='text-right'>Actions</div>,
        cell: ({ row }) => (
          <div className='flex justify-end'>
            <Button
              type='button'
              size='sm'
              variant='outline'
              onClick={(): void => {
                startTransition(() => { router.push(
                                    buildThreadHref({
                                      threadId: row.original.id,
                                      accountId: row.original.accountId,
                                      mailboxPath: row.original.mailboxPath,
                                      originPanel: isRecentPanel ? 'recent' : null,
                                      recentMailboxFilter: isRecentPanel ? effectiveRecentMailboxFilter : null,
                                      recentUnreadOnly: isRecentPanel ? effectiveRecentUnreadOnly : false,
                                      recentQuery: isRecentPanel ? effectiveQuery : null,
                                      recentCampaignId: isRecentPanel ? effectiveRecentCampaignId : null,
                                      recentRunId: isRecentPanel ? effectiveRecentRunId : null,
                                      recentDeliveryId: isRecentPanel ? effectiveRecentDeliveryId : null,
                                    })
                                  ); });
              }}
            >
              Open Thread
            </Button>
          </div>
        ),
      },
    ],
    [
      effectiveQuery,
      effectiveRecentCampaignId,
      effectiveRecentDeliveryId,
      effectiveRecentMailboxFilter,
      effectiveRecentRunId,
      effectiveRecentUnreadOnly,
      isRecentPanel,
      router,
    ]
  );

  const recentMailboxOptions = useMemo(
    () =>
      Array.from(new Set(threads.map((thread) => thread.mailboxPath)))
        .sort((left, right) => left.localeCompare(right))
        .map((mailboxPath) => ({
          value: mailboxPath,
          label: mailboxPath,
        })),
    [threads]
  );

  const visibleThreads = useMemo(() => {
    if (!isRecentPanel) return threads;
    return threads.filter((thread) => {
      if (effectiveRecentMailboxFilter && thread.mailboxPath !== effectiveRecentMailboxFilter) return false;
      if (effectiveRecentUnreadOnly && thread.unreadCount < 1) return false;
      return true;
    });
  }, [effectiveRecentMailboxFilter, effectiveRecentUnreadOnly, isRecentPanel, threads]);

  const tableActions = useMemo(
    () => [
      {
        key: 'compose',
        label: 'Compose',
        icon: <MailPlus className='size-4' />,
        onClick: () =>
          startTransition(() => { router.push(
                        buildComposeHref({
                          accountId: selectedAccountId,
                          mailboxPath: selectedFolder?.mailboxPath ?? null,
                          originPanel: isRecentPanel ? 'recent' : null,
                          recentMailboxFilter: isRecentPanel ? effectiveRecentMailboxFilter : null,
                          recentUnreadOnly: isRecentPanel ? effectiveRecentUnreadOnly : false,
                          recentQuery: isRecentPanel ? effectiveQuery : null,
                          recentCampaignId: isRecentPanel ? effectiveRecentCampaignId : null,
                          recentRunId: isRecentPanel ? effectiveRecentRunId : null,
                          recentDeliveryId: isRecentPanel ? effectiveRecentDeliveryId : null,
                        })
                      ); }),
      },
      ...(selectedAccount
        ? [
            {
              key: 'sync',
              label: syncingAccountId === selectedAccount.id ? 'Syncing...' : 'Sync',
              icon: <RefreshCcw className='size-4' />,
              variant: 'outline' as const,
              disabled: syncingAccountId === selectedAccount.id,
              onClick: () => {
                void handleSyncAccount(selectedAccount.id);
              },
            },
          ]
        : []),
      ...(isRecentPanel && (
        effectiveRecentMailboxFilter ||
        effectiveRecentUnreadOnly ||
        effectiveQuery ||
        effectiveRecentCampaignId ||
        effectiveRecentRunId ||
        effectiveRecentDeliveryId
      )
        ? [
            {
              key: 'clear-recent-filters',
              label: 'Clear Filters',
              icon: <FilterX className='size-4' />,
              variant: 'outline' as const,
              onClick: () => {
                setQuery('');
                setRecentMailboxFilter('');
                setRecentUnreadOnly(false);
                setRecentCampaignId('');
                setRecentRunId('');
                setRecentDeliveryId('');
              },
            },
          ]
        : []),
      {
        key: 'search-messages',
        label: 'Search Messages',
        icon: <Search className='size-4' />,
        variant: 'outline' as const,
        onClick: () =>
          setSelection({
            accountId: selectedAccountId,
            mailboxPath: null,
            panel: 'search',
          }),
      },
      {
        key: 'account',
        label: 'Open Account',
        icon: <Mail className='size-4' />,
        variant: 'outline' as const,
        onClick: () =>
          setSelection({
            accountId: selectedAccountId,
            mailboxPath: null,
            panel: 'settings',
          }),
      },
      ...buildFilemakerNavActions(router, 'mail'),
    ],
    [
      effectiveQuery,
      effectiveRecentCampaignId,
      effectiveRecentDeliveryId,
      effectiveRecentMailboxFilter,
      effectiveRecentRunId,
      effectiveRecentUnreadOnly,
      handleSyncAccount,
      isRecentPanel,
      router,
      selectedAccount,
      selectedAccountId,
      selectedFolder,
      setRecentCampaignId,
      setRecentDeliveryId,
      syncingAccountId,
      setRecentRunId,
    ]
  );

  return {
    accounts,
    setAccounts,
    folders,
    threads,
    recentPreviewThreads,
    selection,
    setSelection,
    isNavigationLoading,
    isThreadsLoading,
    isSavingAccount,
    syncingAccountId,
    setSyncingAccountId,
    draft,
    setDraft,
    accountFormErrors,
    deepSearchQuery: effectiveDeepSearchQuery,
    setDeepSearchQuery,
    deepSearchResults,
    setDeepSearchResults,
    isSearching,
    folderAllowlistValue,
    setFolderAllowlistValue,
    query: effectiveQuery,
    setQuery,
    recentMailboxFilter: effectiveRecentMailboxFilter,
    setRecentMailboxFilter,
    recentUnreadOnly: effectiveRecentUnreadOnly,
    setRecentUnreadOnly,
    recentCampaignId: effectiveRecentCampaignId,
    recentRunId: effectiveRecentRunId,
    recentDeliveryId: effectiveRecentDeliveryId,
    attentionAccounts,
    selectedAccountId,
    selectedMailboxPath,
    selectedPanel,
    selectedAccount,
    selectedFolder,
    selectedAccountLabel,
    selectedFolderLabel,
    isAttentionPanel,
    isSearchPanel,
    isRecentPanel,
    columns,
    recentMailboxOptions,
    visibleThreads,
    tableActions,
    handleSaveAccount,
    handleSyncAccount,
    loadNavigation,
    onNewMailbox,
    router,
  };
}

'use client';

import { Archive, ArrowLeft, Eye, EyeOff, Forward, Paperclip, Reply, Star, StarOff, Trash2 } from 'lucide-react';
import { useRouter } from 'nextjs-toploader/app';
import { useParams, useSearchParams } from 'next/navigation';
import React, { useCallback, useEffect, useMemo, useState, startTransition } from 'react';

import { DocumentWysiwygEditor } from '@/shared/lib/document-editor/public';
import { FilemakerMailSidebar } from '../components/FilemakerMailSidebar';
import { buildFilemakerMailComposeHref as buildComposeHref } from '../components/FilemakerMailSidebar.helpers';
import { buildFilemakerMailThreadHref as buildThreadHref } from '../components/FilemakerMailSidebar.helpers';
import { buildFilemakerMailSelectionHref as buildSelectionHref } from '../mail-ui-helpers';
import { parseFilemakerMailParticipantsInput } from '../mail-utils';
import { sanitizeHtml } from '@/shared/utils/sanitization';

import type { FilemakerMailParticipant, FilemakerMailThreadDetail } from '../types';
import { Badge, Button, Input, useToast } from '@/shared/ui/primitives.public';
import { FormField, FormSection } from '@/shared/ui/forms-and-actions.public';
import { PanelHeader } from '@/shared/ui/templates.public';
import { FilemakerCampaignContextLinks } from './FilemakerCampaignMailLinks';

type ThreadResponse = {
  detail: FilemakerMailThreadDetail;
  forwardDraft: {
    accountId: string;
    bodyHtml: string;
    bcc: FilemakerMailParticipant[];
    cc: FilemakerMailParticipant[];
    inReplyTo: string | null;
    subject: string;
    to: FilemakerMailParticipant[];
  } | null;
  replyDraft: {
    accountId: string;
    to: FilemakerMailParticipant[];
    subject: string;
    bodyHtml: string;
    inReplyTo: string | null;
  } | null;
};

const fetchJson = async <T,>(url: string, init?: RequestInit): Promise<T> => {
  const response = await fetch(url, {
    ...init,
    headers: {
      'content-type': 'application/json',
      ...(init?.headers ?? {}),
    },
  });
  if (!response.ok) {
    throw new Error(`Request failed (${response.status})`);
  }
  return (await response.json()) as T;
};

const formatParticipants = (participants: FilemakerMailParticipant[]): string =>
  participants
    .map((entry) => (entry.name ? `${entry.name} <${entry.address}>` : entry.address))
    .join(', ');

type LoadThreadOptions = {
  preserveReplyDraft?: boolean;
};

export function AdminFilemakerMailThreadPage(): React.JSX.Element {
  const params = useParams();
  const router = useRouter();
  const searchParams = useSearchParams();
  const { toast } = useToast();
  const rawThreadId = Array.isArray(params['threadId']) ? params['threadId'][0] : params['threadId'];
  const threadId = useMemo(() => decodeURIComponent(rawThreadId ?? ''), [rawThreadId]);
  const [detail, setDetail] = useState<FilemakerMailThreadDetail | null>(null);
  const [replyAccountId, setReplyAccountId] = useState('');
  const [replyTo, setReplyTo] = useState('');
  const [replyCc, setReplyCc] = useState('');
  const [replyBcc, setReplyBcc] = useState('');
  const [replySubject, setReplySubject] = useState('');
  const [replyInReplyTo, setReplyInReplyTo] = useState<string | null>(null);
  const [replyHtml, setReplyHtml] = useState('<p><br/></p>');
  const [isLoading, setIsLoading] = useState(true);
  const [isSending, setIsSending] = useState(false);
  const [isTogglingRead, setIsTogglingRead] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  const [sidebarRefreshKey, setSidebarRefreshKey] = useState(0);
  const accountId = searchParams.get('accountId');
  const mailboxPath = searchParams.get('mailboxPath');
  const rawOriginPanel = searchParams.get('panel');
  const originPanel =
    rawOriginPanel === 'recent'
      ? 'recent'
      : rawOriginPanel === 'search'
        ? 'search'
        : null;
  const rawRecentMailboxFilter = searchParams.get('recentMailbox');
  const rawRecentUnreadOnly = searchParams.get('recentUnread') === '1';
  const rawRecentQuery = searchParams.get('recentQuery');
  const rawRecentCampaignId = searchParams.get('campaignId');
  const rawRecentRunId = searchParams.get('runId');
  const rawRecentDeliveryId = searchParams.get('deliveryId');
  const rawSearchQuery = searchParams.get('searchQuery');
  const rawSearchAccountId = searchParams.get('searchAccountId');
  const rawSearchContextAccountId = searchParams.get('searchContextAccountId');
  const recentMailboxFilter =
    originPanel === 'recent' && rawRecentMailboxFilter ? rawRecentMailboxFilter : null;
  const recentUnreadOnly = originPanel === 'recent' ? rawRecentUnreadOnly : false;
  const recentQuery = originPanel === 'recent' && rawRecentQuery ? rawRecentQuery : null;
  const recentCampaignId =
    originPanel === 'recent' && rawRecentCampaignId ? rawRecentCampaignId : null;
  const recentRunId = originPanel === 'recent' && rawRecentRunId ? rawRecentRunId : null;
  const recentDeliveryId =
    originPanel === 'recent' && rawRecentDeliveryId ? rawRecentDeliveryId : null;
  const searchQuery = originPanel === 'search' && rawSearchQuery ? rawSearchQuery : null;
  const searchAccountId =
    originPanel === 'search' && rawSearchAccountId === 'all' ? 'all' : null;
  const isGlobalSearchContext = searchAccountId === 'all';
  const persistedSearchContextAccountId =
    originPanel === 'search' &&
    !isGlobalSearchContext &&
    rawSearchContextAccountId &&
    rawSearchContextAccountId !== accountId
      ? rawSearchContextAccountId
      : null;
  const searchContextAccountId = originPanel === 'search'
    ? isGlobalSearchContext
      ? null
      : persistedSearchContextAccountId ?? accountId
    : null;
  const backLabel =
    originPanel === 'recent'
      ? 'Back to Recent'
      : originPanel === 'search'
        ? 'Back to Search'
        : 'Back to Mail';
  const backHref = useMemo(() => {
    return buildSelectionHref({
      accountId: originPanel === 'search' ? searchContextAccountId : accountId,
      mailboxPath: originPanel ? null : mailboxPath,
      panel: originPanel,
      recentMailboxFilter: originPanel === 'recent' ? recentMailboxFilter : null,
      recentUnreadOnly: originPanel === 'recent' ? recentUnreadOnly : false,
      recentQuery: originPanel === 'recent' ? recentQuery : null,
      recentCampaignId: originPanel === 'recent' ? recentCampaignId : null,
      recentRunId: originPanel === 'recent' ? recentRunId : null,
      recentDeliveryId: originPanel === 'recent' ? recentDeliveryId : null,
      searchQuery: originPanel === 'search' ? searchQuery : null,
    });
  }, [
    accountId,
    mailboxPath,
    originPanel,
    recentCampaignId,
    recentDeliveryId,
    recentMailboxFilter,
    recentQuery,
    recentRunId,
    recentUnreadOnly,
    searchContextAccountId,
    searchQuery,
  ]);
  useEffect(() => {
    if (
      (rawOriginPanel ?? null) === originPanel &&
      (rawRecentMailboxFilter ?? null) === recentMailboxFilter &&
      rawRecentUnreadOnly === recentUnreadOnly &&
      (rawRecentQuery ?? null) === recentQuery &&
      (rawRecentCampaignId ?? null) === recentCampaignId &&
      (rawRecentRunId ?? null) === recentRunId &&
      (rawRecentDeliveryId ?? null) === recentDeliveryId &&
      (rawSearchQuery ?? null) === searchQuery &&
      (rawSearchAccountId ?? null) === searchAccountId &&
      (rawSearchContextAccountId ?? null) === persistedSearchContextAccountId
    ) {
      return;
    }

    startTransition(() => { router.replace(
            buildThreadHref({
              threadId,
              accountId,
              mailboxPath,
              originPanel,
              recentMailboxFilter,
              recentUnreadOnly,
              recentQuery,
              recentCampaignId,
              recentRunId,
              recentDeliveryId,
              searchContextAccountId: persistedSearchContextAccountId,
              searchAccountId,
              searchQuery,
            })
          ); });
  }, [
    accountId,
    mailboxPath,
    originPanel,
    rawOriginPanel,
    rawRecentCampaignId,
    rawRecentDeliveryId,
    rawRecentMailboxFilter,
    rawRecentQuery,
    rawRecentRunId,
    rawRecentUnreadOnly,
    rawSearchAccountId,
    rawSearchContextAccountId,
    rawSearchQuery,
    recentCampaignId,
    recentDeliveryId,
    recentMailboxFilter,
    recentQuery,
    recentRunId,
    recentUnreadOnly,
    persistedSearchContextAccountId,
    router,
    searchAccountId,
    searchQuery,
    threadId,
  ]);

  const load = useCallback(async (options?: LoadThreadOptions): Promise<void> => {
    setIsLoading(true);
    try {
      const result = await fetchJson<ThreadResponse>(
        `/api/filemaker/mail/threads/${encodeURIComponent(threadId)}`
      );
      setDetail(result.detail);
      if (!options?.preserveReplyDraft) {
        setReplyAccountId(result.replyDraft?.accountId ?? '');
        setReplyTo(formatParticipants(result.replyDraft?.to ?? []));
        setReplyCc('');
        setReplyBcc('');
        setReplySubject(result.replyDraft?.subject ?? result.detail.thread.subject);
        setReplyHtml(result.replyDraft?.bodyHtml ?? '<p><br/></p>');
        setReplyInReplyTo(result.replyDraft?.inReplyTo ?? null);
      }
    } catch (error) {
      toast(error instanceof Error ? error.message : 'Failed to load mail thread.', {
        variant: 'error',
      });
    } finally {
      setIsLoading(false);
    }
  }, [threadId, toast]);

  useEffect(() => {
    void load();
  }, [load]);

  const handleReply = async (): Promise<void> => {
    setIsSending(true);
    try {
      await fetchJson('/api/filemaker/mail/send', {
        method: 'POST',
        body: JSON.stringify({
          accountId: replyAccountId,
          threadId,
          inReplyTo: replyInReplyTo,
          to: parseFilemakerMailParticipantsInput(replyTo),
          cc: parseFilemakerMailParticipantsInput(replyCc),
          bcc: parseFilemakerMailParticipantsInput(replyBcc),
          subject: replySubject,
          bodyHtml: replyHtml,
        }),
      });
      toast('Reply sent.', { variant: 'success' });
      await load();
      setSidebarRefreshKey((current) => current + 1);
    } catch (error) {
      toast(error instanceof Error ? error.message : 'Failed to send reply.', {
        variant: 'error',
      });
    } finally {
      setIsSending(false);
    }
  };

  const handleToggleRead = async (): Promise<void> => {
    if (!detail) return;
    setIsTogglingRead(true);
    try {
      const markRead = detail.thread.unreadCount > 0;
      await fetchJson(
        `/api/filemaker/mail/threads/${encodeURIComponent(threadId)}`,
        {
          method: 'PATCH',
          body: JSON.stringify({ read: markRead }),
        }
      );
      toast(markRead ? 'Marked as read.' : 'Marked as unread.', { variant: 'success' });
      await load({ preserveReplyDraft: true });
      setSidebarRefreshKey((current) => current + 1);
    } catch (error) {
      toast(error instanceof Error ? error.message : 'Failed to update thread.', {
        variant: 'error',
      });
    } finally {
      setIsTogglingRead(false);
    }
  };

  const handleDelete = async (): Promise<void> => {
    setIsDeleting(true);
    try {
      await fetchJson(
        `/api/filemaker/mail/threads/${encodeURIComponent(threadId)}`,
        { method: 'DELETE' }
      );
      toast('Thread deleted.', { variant: 'success' });
      startTransition(() => { router.push(backHref); });
    } catch (error) {
      toast(error instanceof Error ? error.message : 'Failed to delete thread.', {
        variant: 'error',
      });
    } finally {
      setIsDeleting(false);
    }
  };

  const [pendingMessageAction, setPendingMessageAction] = useState<string | null>(null);

  const handleToggleFlag = useCallback(async (messageId: string, flagged: boolean): Promise<void> => {
    setPendingMessageAction(`${messageId}:flag`);
    try {
      await fetchJson(`/api/filemaker/mail/messages/${encodeURIComponent(messageId)}/flags`, {
        method: 'PATCH',
        body: JSON.stringify({ flagged }),
      });
      await load({ preserveReplyDraft: true });
    } catch (error) {
      toast(error instanceof Error ? error.message : 'Failed to update flag.', {
        variant: 'error',
      });
    } finally {
      setPendingMessageAction(null);
    }
  }, [load, toast]);

  const handleMoveMessage = useCallback(async (
    messageId: string,
    targetRole: 'archive' | 'trash'
  ): Promise<void> => {
    setPendingMessageAction(`${messageId}:${targetRole}`);
    try {
      await fetchJson(`/api/filemaker/mail/messages/${encodeURIComponent(messageId)}/move`, {
        method: 'POST',
        body: JSON.stringify({ targetRole }),
      });
      toast(targetRole === 'archive' ? 'Archived.' : 'Moved to trash.', { variant: 'success' });
      await load({ preserveReplyDraft: true });
      setSidebarRefreshKey((current) => current + 1);
    } catch (error) {
      toast(error instanceof Error ? error.message : 'Failed to move message.', {
        variant: 'error',
      });
    } finally {
      setPendingMessageAction(null);
    }
  }, [load, toast]);

  const isThreadUnread = (detail?.thread.unreadCount ?? 0) > 0;

  return (
    <div className='page-section-compact grid gap-6 xl:grid-cols-[320px_minmax(0,1fr)]'>
      <FilemakerMailSidebar
        selection={{
          accountId,
          mailboxPath,
          threadId,
          originPanel,
        }}
        filters={{
          recentMailboxFilter,
          recentUnreadOnly,
          recentQuery,
          searchContextAccountId,
          searchQuery,
        }}
        refreshKey={sidebarRefreshKey}
      />

      <div className='space-y-6'>
        <PanelHeader
          title={detail?.thread.subject ?? 'Mail Thread'}
          description='Review synced messages and reply using the shared rich-text editor.'
          icon={<Reply className='size-4' />}
          actions={[
            {
              key: 'back',
              label: backLabel,
              icon: <ArrowLeft className='size-4' />,
              variant: 'outline',
              onClick: () => startTransition(() => { router.push(backHref); }),
            },
            ...(detail
              ? [
                  {
                    key: 'toggle-read',
                    label: isTogglingRead
                      ? 'Updating...'
                      : isThreadUnread
                        ? 'Mark Read'
                        : 'Mark Unread',
                    icon: isThreadUnread
                      ? <Eye className='size-4' />
                      : <EyeOff className='size-4' />,
                    variant: 'outline' as const,
                    disabled: isTogglingRead,
                    onClick: () => { void handleToggleRead(); },
                  },
                  {
                    key: 'forward',
                    label: 'Forward',
                    icon: <Forward className='size-4' />,
                    variant: 'outline' as const,
                    onClick: () => {
                      const lastMessage = detail.messages[detail.messages.length - 1];
                      if (!lastMessage) return;
                      startTransition(() => { router.push(
                                                buildComposeHref({
                                                  accountId: detail.thread.accountId,
                                                  forwardThreadId: threadId,
                                                  mailboxPath: mailboxPath ?? detail.thread.mailboxPath,
                                                  originPanel,
                                                  recentMailboxFilter,
                                                  recentUnreadOnly,
                                                  recentQuery,
                                                  searchContextAccountId: persistedSearchContextAccountId,
                                                  searchAccountId: isGlobalSearchContext ? 'all' : null,
                                                  searchQuery,
                                                })
                                              ); });
                    },
                  },
                  {
                    key: 'delete',
                    label: isDeleting ? 'Deleting...' : 'Delete',
                    icon: <Trash2 className='size-4' />,
                    variant: 'outline' as const,
                    disabled: isDeleting,
                    onClick: () => { void handleDelete(); },
                  },
                ]
              : []),
          ]}
        />

        {detail ? (
          <div className='space-y-4'>
            <div className='flex flex-wrap gap-2'>
              <Badge variant='outline' className='text-[10px]'>
                Messages: {detail.thread.messageCount}
              </Badge>
              <Badge variant='outline' className='text-[10px]'>
                Unread: {detail.thread.unreadCount}
              </Badge>
              <Badge variant='outline' className='text-[10px]'>
                Mailbox: {detail.thread.mailboxPath}
              </Badge>
              {detail.thread.campaignContext ? (
                <FilemakerCampaignContextLinks
                  context={detail.thread.campaignContext}
                  className='flex flex-wrap gap-2'
                />
              ) : null}
            </div>

            <div className='space-y-3'>
              {detail.messages.map((message) => (
                <div
                  key={message.id}
                  className='rounded-lg border border-border/60 bg-card/25 p-4 text-sm text-gray-300'
                >
                  <div className='mb-3 flex flex-wrap items-center justify-between gap-2'>
                    <div>
                      <div className='font-medium text-white'>
                        {message.from?.name ?? message.from?.address ?? 'Unknown sender'}
                      </div>
                      <div className='text-[11px] text-gray-500'>
                        To: {formatParticipants(message.to)}
                      </div>
                      {message.campaignContext ? (
                        <FilemakerCampaignContextLinks
                          context={message.campaignContext}
                          className='mt-2 flex flex-wrap gap-2'
                        />
                      ) : null}
                    </div>
                    <div className='flex items-center gap-2'>
                      <Button
                        type='button'
                        variant='outline'
                        size='sm'
                        disabled={pendingMessageAction === `${message.id}:flag`}
                        onClick={(): void => {
                          void handleToggleFlag(message.id, message.flags?.flagged !== true);
                        }}
                        aria-label={message.flags?.flagged === true ? 'Unstar message' : 'Star message'}
                      >
                        {message.flags?.flagged === true ? (
                          <Star className='size-4 fill-yellow-300 text-yellow-300' />
                        ) : (
                          <StarOff className='size-4' />
                        )}
                      </Button>
                      <Button
                        type='button'
                        variant='outline'
                        size='sm'
                        disabled={pendingMessageAction === `${message.id}:archive`}
                        onClick={(): void => {
                          void handleMoveMessage(message.id, 'archive');
                        }}
                        aria-label='Archive message'
                      >
                        <Archive className='size-4' />
                      </Button>
                      <Button
                        type='button'
                        variant='outline'
                        size='sm'
                        disabled={pendingMessageAction === `${message.id}:trash`}
                        onClick={(): void => {
                          void handleMoveMessage(message.id, 'trash');
                        }}
                        aria-label='Move message to trash'
                      >
                        <Trash2 className='size-4' />
                      </Button>
                      <div className='text-[11px] text-gray-500'>
                        {(message.receivedAt ?? message.sentAt)
                          ? new Date(message.receivedAt ?? message.sentAt ?? '').toLocaleString()
                          : 'Unknown time'}
                      </div>
                    </div>
                  </div>
                  {message.htmlBody ? (
                    <div
                      className='prose prose-invert max-w-none prose-a:text-sky-300'
                      dangerouslySetInnerHTML={{ __html: sanitizeHtml(message.htmlBody) }}
                    />
                  ) : (
                    <pre className='whitespace-pre-wrap text-sm text-gray-300'>
                      {message.textBody ?? '(no content)'}
                    </pre>
                  )}
                  {(message.attachments ?? []).length > 0 ? (
                    <div className='mt-3 flex flex-wrap gap-2 border-t border-border/40 pt-2'>
                      {(message.attachments ?? []).map((attachment) => (
                        <div
                          key={attachment.id}
                          className='inline-flex items-center gap-2 rounded-md border border-border/60 bg-background/40 px-2 py-1 text-[11px] text-gray-300'
                        >
                          <Paperclip className='size-3' />
                          <span className='font-mono'>{attachment.fileName ?? 'attachment'}</span>
                          {typeof attachment.sizeBytes === 'number' ? (
                            <span className='text-gray-500'>
                              {(attachment.sizeBytes / 1024).toFixed(1)} KB
                            </span>
                          ) : null}
                        </div>
                      ))}
                    </div>
                  ) : null}
                </div>
              ))}
            </div>

            <FormSection title='Reply' className='space-y-4 p-4'>
              <FormField label='To'>
                <Input value={replyTo} onChange={(event) => setReplyTo(event.target.value)} />
              </FormField>
              <div className='grid gap-3 md:grid-cols-2'>
                <FormField label='Cc'>
                  <Input
                    value={replyCc}
                    onChange={(event) => setReplyCc(event.target.value)}
                    placeholder='cc@example.com'
                  />
                </FormField>
                <FormField label='Bcc'>
                  <Input
                    value={replyBcc}
                    onChange={(event) => setReplyBcc(event.target.value)}
                    placeholder='bcc@example.com'
                  />
                </FormField>
              </div>
              <FormField label='Subject'>
                <Input
                  value={replySubject}
                  onChange={(event) => setReplySubject(event.target.value)}
                />
              </FormField>
              <DocumentWysiwygEditor
                engineInstance='filemaker_email'
                showBrand
                value={replyHtml}
                onChange={setReplyHtml}
                placeholder='Write your reply...'
              />
              <div className='flex justify-end'>
                <Button
                  type='button'
                  onClick={(): void => {
                    void handleReply();
                  }}
                  disabled={isSending || isLoading}
                >
                  {isSending ? 'Sending reply...' : 'Send Reply'}
                </Button>
              </div>
            </FormSection>
          </div>
        ) : null}
      </div>
    </div>
  );
}

